package com.datamaster.module.assets.controller.admin.sensitiveLevel;import cn.hutool.core.date.DateUtil;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import com.datamaster.common.annotation.Log;import com.datamaster.common.core.controller.BaseController;import com.datamaster.common.core.domain.AjaxResult;import com.datamaster.common.core.domain.CommonResult;import com.datamaster.common.core.page.PageParam;import com.datamaster.common.core.page.PageResult;import com.datamaster.common.enums.BusinessType;import com.datamaster.common.utils.object.BeanUtils;import com.datamaster.common.utils.poi.ExcelUtil;import com.datamaster.module.assets.controller.admin.sensitiveLevel.vo.AssetsSensitiveLevelPageReqVO;import com.datamaster.module.assets.controller.admin.sensitiveLevel.vo.AssetsSensitiveLevelRespVO;import com.datamaster.module.assets.controller.admin.sensitiveLevel.vo.AssetsSensitiveLevelSaveReqVO;import com.datamaster.module.assets.convert.sensitiveLevel.AssetsSensitiveLevelConvert;import com.datamaster.module.assets.dal.dataobject.sensitiveLevel.AssetsSensitiveLevelDO;import com.datamaster.module.assets.service.sensitiveLevel.IAssetsSensitiveLevelService;import javax.annotation.Resource;import javax.servlet.http.HttpServletResponse;import javax.validation.Valid;import java.util.Arrays;import java.util.List;/** * 敏感等级Controller * * @author DATAMASTER * @date 2025-01-21 */@Tag(name = "敏感等级")@RestController@RequestMapping("/ast/sensitiveLevel")@Validated
public class AssetsSensitiveLevelController extends BaseController {    @Resource    private IAssetsSensitiveLevelService AssetsSensitiveLevelService;    @Operation(summary = "查询敏感等级列表")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsSensitiveLevelRespVO>> list(AssetsSensitiveLevelPageReqVO AssetsSensitiveLevel) {        PageResult<AssetsSensitiveLevelDO> page = AssetsSensitiveLevelService.getDaSensitiveLevelPage(AssetsSensitiveLevel);        return CommonResult.success(BeanUtils.toBean(page, AssetsSensitiveLevelRespVO.class));    }    @Operation(summary = "导出敏感等级列表")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:export')")    @Log(title = "敏感等级", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsSensitiveLevelPageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsSensitiveLevelDO> list = (List<AssetsSensitiveLevelDO>) AssetsSensitiveLevelService.getDaSensitiveLevelPage(exportReqVO).getRows();        ExcelUtil<AssetsSensitiveLevelRespVO> util = new ExcelUtil<>(AssetsSensitiveLevelRespVO.class);        util.exportExcel(response, AssetsSensitiveLevelConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入敏感等级列表")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:import')")    @Log(title = "敏感等级", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsSensitiveLevelRespVO> util = new ExcelUtil<>(AssetsSensitiveLevelRespVO.class);        List<AssetsSensitiveLevelRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsSensitiveLevelService.importDaSensitiveLevel(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取敏感等级详细信息")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsSensitiveLevelRespVO> getInfo(@PathVariable("id") Long id) {        AssetsSensitiveLevelDO AssetsSensitiveLevelDO = AssetsSensitiveLevelService.getDaSensitiveLevelById(id);        return CommonResult.success(BeanUtils.toBean(AssetsSensitiveLevelDO, AssetsSensitiveLevelRespVO.class));    }    @Operation(summary = "新增敏感等级")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:add')")    @Log(title = "敏感等级", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsSensitiveLevelSaveReqVO AssetsSensitiveLevel) {        AssetsSensitiveLevel.setCreatorId(getUserId());        AssetsSensitiveLevel.setCreateBy(getNickName());        AssetsSensitiveLevel.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsSensitiveLevelService.createDaSensitiveLevel(AssetsSensitiveLevel));    }    @Operation(summary = "修改敏感等级")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:edit')")    @Log(title = "敏感等级", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsSensitiveLevelSaveReqVO AssetsSensitiveLevel) {        AssetsSensitiveLevel.setUpdatorId(getUserId());        AssetsSensitiveLevel.setUpdateBy(getNickName());        AssetsSensitiveLevel.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsSensitiveLevelService.updateDaSensitiveLevel(AssetsSensitiveLevel));    }    @Operation(summary = "修改敏感等级状态")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:edit')")    @Log(title = "敏感等级", businessType = BusinessType.UPDATE)    @PostMapping("/updateStatus/{id}/{status}")    public AjaxResult updateStatus(@PathVariable Long id, @PathVariable Long status) {        if (!AssetsSensitiveLevelService.updateStatus(id,status)){            return AjaxResult.error("已被使用，不允许下线！");        }        return AjaxResult.success("修改成功");    }    @Operation(summary = "删除敏感等级")    @PreAuthorize("@ss.hasPermi('da:sensitiveLevel:remove')")    @Log(title = "敏感等级", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsSensitiveLevelService.removeDaSensitiveLevel(Arrays.asList(ids)));    }}